<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  * { box-sizing: border-box; }
  body {
    margin: 0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: #f0f2f5;
    color: #1c1e21;
    min-height: 100vh;
  }
  header.app-header {
    padding: 24px 32px 8px;
  }
  header.app-header h1 {
    margin: 0 0 16px;
    font-size: 24px;
    font-weight: 700;
  }
  .add-row {
    display: flex;
    gap: 8px;
    max-width: 480px;
  }
  #new-card {
    flex: 1;
    padding: 10px 14px;
    border: 1px solid #ccd0d5;
    border-radius: 8px;
    font-size: 15px;
    outline: none;
    transition: border-color .15s, box-shadow .15s;
  }
  #new-card:focus {
    border-color: #4f7bff;
    box-shadow: 0 0 0 3px rgba(79,123,255,.2);
  }
  #add-card {
    padding: 10px 20px;
    border: none;
    border-radius: 8px;
    background: #4f7bff;
    color: #fff;
    font-size: 15px;
    font-weight: 600;
    cursor: pointer;
    transition: background .15s;
  }
  #add-card:hover { background: #3a63d8; }
  #add-card:active { transform: translateY(1px); }

  .board {
    display: flex;
    gap: 20px;
    padding: 24px 32px 40px;
    align-items: flex-start;
    overflow-x: auto;
  }
  .column {
    flex: 1 1 0;
    min-width: 260px;
    background: #ebedf0;
    border-radius: 12px;
    padding: 12px;
    transition: background .15s, box-shadow .15s;
  }
  .column.drag-over {
    background: #dfe6ff;
    box-shadow: inset 0 0 0 2px #4f7bff;
  }
  .col-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 4px 8px 12px;
  }
  .col-header h2 {
    margin: 0;
    font-size: 15px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: .04em;
    color: #444;
  }
  .count {
    background: #ccd0d5;
    color: #333;
    font-size: 13px;
    font-weight: 700;
    min-width: 24px;
    text-align: center;
    padding: 2px 8px;
    border-radius: 12px;
  }
  .cards {
    min-height: 60px;
    display: flex;
    flex-direction: column;
    gap: 10px;
  }
  .card {
    background: #fff;
    border-radius: 8px;
    padding: 12px 14px;
    box-shadow: 0 1px 2px rgba(0,0,0,.12), 0 1px 1px rgba(0,0,0,.06);
    cursor: grab;
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 8px;
    word-break: break-word;
    transition: box-shadow .15s, transform .05s;
  }
  .card:hover { box-shadow: 0 3px 8px rgba(0,0,0,.16); }
  .card.dragging { opacity: .5; cursor: grabbing; }
  .card-title { flex: 1; font-size: 15px; line-height: 1.35; }
  .card-del {
    border: none;
    background: transparent;
    color: #b0b3b8;
    font-size: 18px;
    line-height: 1;
    cursor: pointer;
    padding: 0 2px;
    border-radius: 4px;
    transition: color .15s, background .15s;
  }
  .card-del:hover { color: #e23; background: #ffe5e9; }
</style>
</head>
<body>
  <header class="app-header">
    <h1>Kanban Board</h1>
    <div class="add-row">
      <input id="new-card" type="text" placeholder="Add a card to To Do…" autocomplete="off">
      <button id="add-card">Add</button>
    </div>
  </header>

  <main class="board">
    <section class="column" id="col-todo" data-col="todo">
      <div class="col-header">
        <h2>To Do</h2>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>

    <section class="column" id="col-doing" data-col="doing">
      <div class="col-header">
        <h2>Doing</h2>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>

    <section class="column" id="col-done" data-col="done">
      <div class="col-header">
        <h2>Done</h2>
        <span class="count">0</span>
      </div>
      <div class="cards"></div>
    </section>
  </main>

<script>
(function () {
  "use strict";

  var STORAGE_KEY = "kanban.board.v1";
  var COLUMNS = ["todo", "doing", "done"];

  // state: array of { id, title, col }
  var state = load();
  var counter = state.reduce(function (m, c) {
    var n = parseInt(c.id.replace(/\D/g, ""), 10);
    return isNaN(n) ? m : Math.max(m, n);
  }, 0);

  function load() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      var parsed = JSON.parse(raw);
      if (!Array.isArray(parsed)) return [];
      return parsed.filter(function (c) {
        return c && typeof c.id === "string" &&
               typeof c.title === "string" &&
               COLUMNS.indexOf(c.col) !== -1;
      });
    } catch (e) {
      return [];
    }
  }

  function save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    } catch (e) { /* ignore quota errors */ }
  }

  function colContainer(col) {
    return document.querySelector("#col-" + col + " .cards");
  }
  function colCountEl(col) {
    return document.querySelector("#col-" + col + " .count");
  }

  function updateCounts() {
    COLUMNS.forEach(function (col) {
      var n = state.filter(function (c) { return c.col === col; }).length;
      colCountEl(col).textContent = n;
    });
  }

  function makeCardEl(card) {
    var el = document.createElement("div");
    el.className = "card";
    el.setAttribute("draggable", "true");
    el.dataset.id = card.id;

    var title = document.createElement("span");
    title.className = "card-title";
    title.textContent = card.title;

    var del = document.createElement("button");
    del.className = "card-del";
    del.type = "button";
    del.setAttribute("aria-label", "Delete card");
    del.textContent = "\u00d7";
    del.addEventListener("click", function (e) {
      e.stopPropagation();
      deleteCard(card.id);
    });

    el.appendChild(title);
    el.appendChild(del);

    el.addEventListener("dragstart", function (e) {
      el.classList.add("dragging");
      e.dataTransfer.effectAllowed = "move";
      e.dataTransfer.setData("text/plain", card.id);
    });
    el.addEventListener("dragend", function () {
      el.classList.remove("dragging");
    });

    return el;
  }

  function render() {
    COLUMNS.forEach(function (col) {
      colContainer(col).innerHTML = "";
    });
    state.forEach(function (card) {
      colContainer(card.col).appendChild(makeCardEl(card));
    });
    updateCounts();
  }

  function addCard(title) {
    title = title.trim();
    if (!title) return;
    counter += 1;
    state.push({ id: "card-" + counter, title: title, col: "todo" });
    save();
    render();
  }

  function deleteCard(id) {
    state = state.filter(function (c) { return c.id !== id; });
    save();
    render();
  }

  function moveCard(id, col) {
    if (COLUMNS.indexOf(col) === -1) return;
    var card = state.filter(function (c) { return c.id === id; })[0];
    if (!card || card.col === col) return;
    card.col = col;
    save();
    render();
  }

  // --- wire up controls ---
  var input = document.getElementById("new-card");
  var addBtn = document.getElementById("add-card");

  addBtn.addEventListener("click", function () {
    addCard(input.value);
    input.value = "";
    input.focus();
  });
  input.addEventListener("keydown", function (e) {
    if (e.key === "Enter") {
      addCard(input.value);
      input.value = "";
    }
  });

  // --- drag-and-drop on columns ---
  COLUMNS.forEach(function (col) {
    var column = document.getElementById("col-" + col);

    column.addEventListener("dragover", function (e) {
      e.preventDefault();
      e.dataTransfer.dropEffect = "move";
      column.classList.add("drag-over");
    });
    column.addEventListener("dragleave", function (e) {
      if (!column.contains(e.relatedTarget)) {
        column.classList.remove("drag-over");
      }
    });
    column.addEventListener("drop", function (e) {
      e.preventDefault();
      column.classList.remove("drag-over");
      var id = e.dataTransfer.getData("text/plain");
      if (id) moveCard(id, col);
    });
  });

  render();
})();
</script>
</body>
</html>
